if (! function_exists('math_statistics')) {
    function math_statistics($numbers, $measures = null)
    {
        $nums = $numbers;
        $measures = isset($measures) ? $measures : ['mean','median','mode','range','variance','stdev','min','max','sum','count','quartiles'];
        if (empty($nums)) return json_encode(['error' => 'Empty array', 'count' => 0]);
        $count = count($nums);
        $sum = array_sum($nums);
        $min = min($nums);
        $max = max($nums);
        $result = ['count' => $count];
        $sorted = $nums;
        sort($sorted);
        foreach ($measures as $m) {
            switch ($m) {
                case 'sum': $result['sum'] = round($sum, 6); break;
                case 'min': $result['min'] = $min; break;
                case 'max': $result['max'] = $max; break;
                case 'mean': $result['mean'] = round($sum / $count, 6); break;
                case 'median':
                    $mid = (int)floor($count / 2);
                    $result['median'] = ($count % 2 === 0) ? round(($sorted[$mid-1] + $sorted[$mid]) / 2, 6) : $sorted[$mid];
                    break;
                case 'mode':
                    // Custom frequency counting that works with floats
                    $freq = [];
                    foreach ($nums as $v) {
                        $key = (string)round($v, 6);
                        $freq[$key] = ($freq[$key] ?? 0) + 1;
                    }
                    $maxFreq = max($freq);
                    $modes = [];
                    foreach ($freq as $key => $f) {
                        if ($f === $maxFreq) {
                            $modes[] = (float)$key;
                        }
                    }
                    $result['mode'] = $modes;
                    $result['mode_frequency'] = $maxFreq;
                    break;
                case 'range': $result['range'] = round($max - $min, 6); break;
                case 'variance':
                    $mean = $sum / $count;
                    $var = 0;
                    foreach ($nums as $v) $var += pow($v - $mean, 2);
                    $result['variance'] = round($var / $count, 6);
                    $result['variance_sample'] = $count > 1 ? round($var / ($count - 1), 6) : null;
                    break;
                case 'stdev':
                    $mean = $sum / $count;
                    $var = 0;
                    foreach ($nums as $v) $var += pow($v - $mean, 2);
                    $result['stdev'] = round(sqrt($var / $count), 6);
                    $result['stdev_sample'] = $count > 1 ? round(sqrt($var / ($count - 1)), 6) : null;
                    break;
                case 'quartiles':
                    // R-type 7 interpolation for quartiles
                    $q1Idx = ($count - 1) * 0.25;
                    $q2Idx = ($count - 1) * 0.5;
                    $q3Idx = ($count - 1) * 0.75;
                    
                    $interp = function($idx) use ($sorted) {
                        $lo = (int)floor($idx);
                        $hi = (int)ceil($idx);
                        $frac = $idx - $lo;
                        if ($lo === $hi || $frac == 0) return $sorted[$lo];
                        return $sorted[$lo] * (1 - $frac) + $sorted[min($hi, count($sorted)-1)] * $frac;
                    };
                    
                    $result['q1'] = round($interp($q1Idx), 6);
                    $result['q2'] = round($interp($q2Idx), 6);
                    $result['q3'] = round($interp($q3Idx), 6);
                    $result['iqr'] = round($result['q3'] - $result['q1'], 6);
                    break;
            }
        }
        return json_encode($result);
    }
